import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import api from "../../api/axios";
import { addSale } from "../../api/saleApi";

export default function AddSale() {
  const navigate = useNavigate();
  const [vehicles, setVehicles] = useState([]);
  const [leads, setLeads] = useState([]);

  const [sale, setSale] = useState({
    vehicle: "",
    customer: "",
    quotedPrice: "",
    finalPrice: "",
    dealStatus: "initiated",
    paymentStatus: "pending",
    paidAmount: 0,
    notes: "",
  });

  useEffect(() => {
    const load = async () => {
      const [vRes, lRes] = await Promise.all([api.get("/vehicles"), api.get("/leads")]);
      const available = vRes.data.filter((v) => v.status === "available");
      setVehicles(available);
      setLeads(lRes.data);

      if (available.length) setSale((p) => ({ ...p, vehicle: available[0]._id }));
      if (lRes.data.length) setSale((p) => ({ ...p, customer: lRes.data[0]._id }));
    };

    load().catch((err) => alert(err.response?.data?.message || "Failed to load"));
  }, []);

  const handleChange = (e) => setSale({ ...sale, [e.target.name]: e.target.value });

  const submit = async (e) => {
    e.preventDefault();
    try {
      await addSale({
        vehicle: sale.vehicle,
        customer: sale.customer,
        quotedPrice: Number(sale.quotedPrice || 0),
        finalPrice: Number(sale.finalPrice || 0),
        paidAmount: Number(sale.paidAmount || 0),
        dealStatus: sale.dealStatus,
        paymentStatus: sale.paymentStatus,
        notes: sale.notes,
      });

      alert("Sale saved!");
      navigate("/sales");
    } catch (err) {
      console.log("ADD SALE ERROR:", err.response?.status, err.response?.data);
      alert(err.response?.data?.message || "Failed to save sale");
    }
  };

  return (
    <div style={{ padding: 20, maxWidth: 520 }}>
      <h2>Add Sale</h2>

      <form onSubmit={submit}>
        <label>Vehicle</label><br />
        <select name="vehicle" value={sale.vehicle} onChange={handleChange} required style={{ width: "100%", padding: 10 }}>
          {vehicles.length === 0 && <option value="">No available vehicles</option>}
          {vehicles.map((v) => (
            <option key={v._id} value={v._id}>
              {v.brand} {v.model || v.type || ""} ({v.year})
            </option>
          ))}
        </select>

        <br /><br />

        <label>Customer (Lead)</label><br />
        <select name="customer" value={sale.customer} onChange={handleChange} required style={{ width: "100%", padding: 10 }}>
          {leads.length === 0 && <option value="">No leads</option>}
          {leads.map((l) => (
            <option key={l._id} value={l._id}>
              {l.name} - {l.contact_number}
            </option>
          ))}
        </select>

        <br /><br />

        <label>Deal Status</label><br />
        <select name="dealStatus" value={sale.dealStatus} onChange={handleChange} style={{ width: "100%", padding: 10 }}>
          <option value="initiated">Initiated</option>
          <option value="completed">Completed</option>
          <option value="cancelled">Cancelled</option>
        </select>

        <br /><br />

        <label>Payment Status</label><br />
        <select name="paymentStatus" value={sale.paymentStatus} onChange={handleChange} style={{ width: "100%", padding: 10 }}>
          <option value="pending">Pending</option>
          <option value="partial">Partial</option>
          <option value="completed">Completed</option>
        </select>

        <br /><br />

        <label>Quoted Price</label><br />
        <input name="quotedPrice" type="number" min="0" value={sale.quotedPrice} onChange={handleChange} style={{ width: "100%", padding: 10 }} />

        <br /><br />

        <label>Final Price</label><br />
        <input name="finalPrice" type="number" min="0" value={sale.finalPrice} onChange={handleChange} style={{ width: "100%", padding: 10 }} />

        <br /><br />

        <label>Paid Amount</label><br />
        <input name="paidAmount" type="number" min="0" value={sale.paidAmount} onChange={handleChange} style={{ width: "100%", padding: 10 }} />

        <br /><br />

        <label>Notes</label><br />
        <textarea name="notes" rows={3} value={sale.notes} onChange={handleChange} style={{ width: "100%", padding: 10 }} />

        <br /><br />

        <button type="submit" style={{ padding: "10px 14px" }}>
          Save Sale
        </button>
      </form>
    </div>
  );
}
